package com.tradepulseai.stockservice.service;

import com.tradepulseai.stockservice.model.Stock;
import com.tradepulseai.stockservice.repository.StockRepository;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.boot.ApplicationArguments;
import org.springframework.boot.ApplicationRunner;
import org.springframework.core.annotation.Order;
import org.springframework.scheduling.annotation.EnableScheduling;
import org.springframework.scheduling.annotation.Scheduled;
import org.springframework.stereotype.Component;

import java.time.LocalDate;
import java.time.ZoneId;
import java.util.List;
import java.util.concurrent.atomic.AtomicBoolean;

/**
 * Scheduled service to fetch daily news and update sentiment for stocks.
 * Runs daily after market close to aggregate news for that trading day.
 */
@Component
@EnableScheduling
@Order(4)
public class NewsIntegrationScheduler implements ApplicationRunner {

    private static final Logger log = LoggerFactory.getLogger(NewsIntegrationScheduler.class);

    private final NewsService newsService;
    private final StockRepository stockRepository;
    private final AtomicBoolean running = new AtomicBoolean(false);

    public NewsIntegrationScheduler(
            NewsService newsService,
            StockRepository stockRepository) {
        this.newsService = newsService;
        this.stockRepository = stockRepository;
    }

    @Override
    public void run(ApplicationArguments args) throws Exception {
        log.info("News Integration Scheduler initialized");
    }

    /**
     * Runs daily at 4 PM UTC (after US market close)
     * Fetches news for the trading day and updates sentiment
     */
    @Scheduled(cron = "0 0 16 * * MON-FRI", zone = "UTC")
    public void fetchDailyNews() {
        if (running.getAndSet(true)) {
            log.warn("News fetch already in progress, skipping");
            return;
        }

        try {
            LocalDate tradingDate = LocalDate.now(ZoneId.of("UTC"));
            log.info("Starting daily news fetch for {}", tradingDate);

            List<Stock> stocks = stockRepository.findAllByOrderByStockIdAsc();
            int processed = 0;
            int errors = 0;

            for (Stock stock : stocks) {
                try {
                    newsService.fetchAndUpdateNewsSentiment(stock, tradingDate);
                    processed++;

                    // Rate limit to avoid API throttling
                    if (processed % 10 == 0) {
                        Thread.sleep(100);
                    }
                } catch (Exception e) {
                    log.error("Error fetching news for stock {}", stock.getSymbol(), e);
                    errors++;
                }
            }

            log.info("Daily news fetch completed: {} processed, {} errors", processed, errors);

        } catch (Exception e) {
            log.error("Error in daily news fetch", e);
        } finally {
            running.set(false);
        }
    }

    /**
     * Manual trigger for backfilling historical news for a specific stock
     */
    public void backfillNewsForStock(String ticker, int daysBack) {
        log.info("Starting backfill of news for {} (last {} days)", ticker, daysBack);

        try {
            Stock stock = stockRepository.findBySymbol(ticker)
                .orElseThrow(() -> new IllegalArgumentException("Stock not found: " + ticker));

            LocalDate endDate = LocalDate.now();
            for (int i = 0; i < daysBack; i++) {
                LocalDate date = endDate.minusDays(i);
                // Skip weekends
                if (date.getDayOfWeek().getValue() < 6) {
                    newsService.fetchAndUpdateNewsSentiment(stock, date);
                    Thread.sleep(50); // Rate limit
                }
            }

            log.info("Backfill completed for {}", ticker);
        } catch (Exception e) {
            log.error("Error backfilling news for {}", ticker, e);
        }
    }
}

package com.tradepulseai.stockservice.service;

import com.tradepulseai.stockservice.model.Stock;
import com.tradepulseai.stockservice.model.StockMarketData;
import com.tradepulseai.stockservice.repository.StockMarketDataRepository;
import com.tradepulseai.stockservice.repository.StockRepository;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Service;
import org.springframework.web.client.RestClient;
import org.springframework.web.util.UriComponentsBuilder;
import tools.jackson.databind.JsonNode;

import java.math.BigDecimal;
import java.time.LocalDate;
import java.time.format.DateTimeFormatter;
import java.util.ArrayList;
import java.util.List;
import java.util.Optional;

@Service
public class NewsService {

    private static final Logger log = LoggerFactory.getLogger(NewsService.class);

    private final RestClient restClient;
    private final StockMarketDataRepository stockMarketDataRepository;
    private final String apiKey;
    private final String apiBaseUrl;
    private final boolean newsIntegrationEnabled;

    public NewsService(
            @Value("${massive.api.base-url}") String apiBaseUrl,
            @Value("${massive.api.key:}") String apiKey,
            @Value("${massive.news.integration-enabled:false}") boolean newsIntegrationEnabled,
            StockMarketDataRepository stockMarketDataRepository) {
        this.restClient = RestClient.create();
        this.stockMarketDataRepository = stockMarketDataRepository;
        this.apiKey = apiKey;
        this.apiBaseUrl = apiBaseUrl;
        this.newsIntegrationEnabled = newsIntegrationEnabled;
    }

    /**
     * Fetch daily news for a stock and update sentiment data
     */
    public void fetchAndUpdateNewsSentiment(Stock stock, LocalDate tradingDate) {
        if (!newsIntegrationEnabled || apiKey == null || apiKey.isBlank()) {
            log.debug("News integration disabled or API key not configured");
            return;
        }

        try {
            Optional<StockMarketData> marketDataOpt = 
                stockMarketDataRepository.findByStockAndTradingDate(stock, tradingDate);

            if (marketDataOpt.isEmpty()) {
                log.debug("No market data found for stock {} on {}", stock.getSymbol(), tradingDate);
                return;
            }

            StockMarketData marketData = marketDataOpt.get();

            // Fetch news for this stock
            List<NewsArticle> articles = fetchNewsForStock(stock.getSymbol(), tradingDate);

            if (articles.isEmpty()) {
                log.debug("No news found for {} on {}", stock.getSymbol(), tradingDate);
                marketData.setNewsCount(0);
                marketData.setDailySentiment("neutral");
                marketData.setSentimentScore(BigDecimal.ZERO);
                stockMarketDataRepository.save(marketData);
                return;
            }

            // Aggregate sentiment
            SentimentAggregation sentiment = aggregateSentiment(articles);

            marketData.setNewsCount(articles.size());
            marketData.setDailySentiment(sentiment.label);
            marketData.setSentimentScore(new BigDecimal(sentiment.score).setScale(4, java.math.RoundingMode.HALF_UP));
            marketData.setNewsSummary(sentiment.summary);
            marketData.setNewsSources(sentiment.sources);
            marketData.setSentimentReasoning(sentiment.reasoning);

            stockMarketDataRepository.save(marketData);
            log.info("Updated sentiment for {} on {} -> {} ({})", 
                stock.getSymbol(), tradingDate, sentiment.label, sentiment.score);

        } catch (Exception e) {
            log.error("Error fetching news for {} on {}", stock.getSymbol(), tradingDate, e);
        }
    }

    private List<NewsArticle> fetchNewsForStock(String ticker, LocalDate date) {
        List<NewsArticle> articles = new ArrayList<>();

        try {
            LocalDate startDate = date;
            LocalDate endDate = date.plusDays(1);

            String url = UriComponentsBuilder
                .fromHttpUrl(apiBaseUrl + "/v2/reference/news")
                .queryParam("ticker", ticker)
                .queryParam("published_utc.gte", startDate.format(DateTimeFormatter.ISO_DATE))
                .queryParam("published_utc.lt", endDate.format(DateTimeFormatter.ISO_DATE))
                .queryParam("limit", 100)
                .queryParam("sort", "published_utc")
                .queryParam("apiKey", apiKey)
                .toUriString();

            String response = restClient.get()
                .uri(url)
                .retrieve()
                .body(String.class);

            if (response == null) {
                return articles;
            }

            JsonNode root = new tools.jackson.databind.ObjectMapper().readTree(response);
            JsonNode results = root.get("results");

            if (results != null && results.isArray()) {
                for (JsonNode result : results) {
                    NewsArticle article = parseNewsArticle(result);
                    if (article != null) {
                        articles.add(article);
                    }
                }
            }

        } catch (Exception e) {
            log.error("Error fetching news from Polygon.io for {}", ticker, e);
        }

        return articles;
    }

    private NewsArticle parseNewsArticle(JsonNode node) {
        try {
            NewsArticle article = new NewsArticle();
            article.title = node.get("title") != null ? node.get("title").asText() : "";
            article.description = node.get("description") != null ? node.get("description").asText() : "";
            article.author = node.get("author") != null ? node.get("author").asText() : "";
            article.url = node.get("article_url") != null ? node.get("article_url").asText() : "";

            // Extract sentiment from insights
            JsonNode insights = node.get("insights");
            if (insights != null && insights.isArray() && insights.size() > 0) {
                JsonNode firstInsight = insights.get(0);
                String sentiment = firstInsight.get("sentiment") != null ? 
                    firstInsight.get("sentiment").asText() : "neutral";
                String reasoning = firstInsight.get("sentiment_reasoning") != null ?
                    firstInsight.get("sentiment_reasoning").asText() : "";

                article.sentiment = sentiment;
                article.reasoning = reasoning;
            }

            // Extract publisher
            JsonNode publisher = node.get("publisher");
            if (publisher != null) {
                article.publisher = publisher.get("name") != null ? 
                    publisher.get("name").asText() : "Unknown";
            }

            return article;
        } catch (Exception e) {
            log.error("Error parsing news article", e);
            return null;
        }
    }

    private SentimentAggregation aggregateSentiment(List<NewsArticle> articles) {
        SentimentAggregation agg = new SentimentAggregation();

        int positive = 0, negative = 0, neutral = 0;
        List<String> publishers = new ArrayList<>();
        StringBuilder summary = new StringBuilder();

        for (NewsArticle article : articles) {
            if ("positive".equalsIgnoreCase(article.sentiment)) {
                positive++;
            } else if ("negative".equalsIgnoreCase(article.sentiment)) {
                negative++;
            } else {
                neutral++;
            }

            if (!article.publisher.isEmpty() && !publishers.contains(article.publisher)) {
                publishers.add(article.publisher);
            }

            if (summary.length() < 500) {
                summary.append(article.title).append("; ");
            }
        }

        // Calculate composite sentiment score (-1.0 to 1.0)
        int total = articles.size();
        double score = (double)(positive - negative) / total;

        // Determine sentiment label
        if (score > 0.2) {
            agg.label = "positive";
        } else if (score < -0.2) {
            agg.label = "negative";
        } else {
            agg.label = "neutral";
        }

        agg.score = score;
        agg.summary = summary.toString();
        agg.sources = String.join(",", publishers);
        agg.reasoning = String.format(
            "News sentiment analysis: %d positive, %d negative, %d neutral articles (score: %.2f)",
            positive, negative, neutral, score
        );

        return agg;
    }

    static class NewsArticle {
        String title;
        String description;
        String author;
        String url;
        String sentiment = "neutral";
        String reasoning;
        String publisher = "Unknown";
    }

    static class SentimentAggregation {
        String label;
        double score;
        String summary;
        String sources;
        String reasoning;
    }
}

-- Migration: Add sentiment and news columns to stock_daily_ohlc table
-- This migration adds support for daily news sentiment analysis

ALTER TABLE stock_daily_ohlc ADD COLUMN IF NOT EXISTS daily_sentiment VARCHAR(20);
ALTER TABLE stock_daily_ohlc ADD COLUMN IF NOT EXISTS sentiment_score NUMERIC(5, 4);
ALTER TABLE stock_daily_ohlc ADD COLUMN IF NOT EXISTS news_count INT DEFAULT 0;
ALTER TABLE stock_daily_ohlc ADD COLUMN IF NOT EXISTS news_summary TEXT;
ALTER TABLE stock_daily_ohlc ADD COLUMN IF NOT EXISTS news_sources VARCHAR(500);
ALTER TABLE stock_daily_ohlc ADD COLUMN IF NOT EXISTS sentiment_reasoning TEXT;

-- Create index for sentiment queries
CREATE INDEX IF NOT EXISTS idx_stock_daily_ohlc_sentiment 
ON stock_daily_ohlc(stock_id, trading_date, daily_sentiment);

-- Add comments for documentation
COMMENT ON COLUMN stock_daily_ohlc.daily_sentiment IS 'Daily sentiment label: positive, negative, or neutral';
COMMENT ON COLUMN stock_daily_ohlc.sentiment_score IS 'Daily sentiment score: -1.0 (very negative) to 1.0 (very positive)';
COMMENT ON COLUMN stock_daily_ohlc.news_count IS 'Number of news articles published for this stock on this date';
COMMENT ON COLUMN stock_daily_ohlc.news_summary IS 'Concatenated titles of news articles for the day';
COMMENT ON COLUMN stock_daily_ohlc.news_sources IS 'Comma-separated list of news publishers';
COMMENT ON COLUMN stock_daily_ohlc.sentiment_reasoning IS 'Explanation of sentiment: positive count, negative count, neutral count, and composite score';
